import{_ as e,a as i,b as t,c as o}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as n,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Aggiungere un canale WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/webdav.md","filePath":"it-IT/upload/webdav.md","lastUpdated":1781962217000}'),c={name:"it-IT/upload/webdav.md"};function s(p,a,u,h,m,g){return l(),d("div",null,[...a[0]||(a[0]=[r('<h1 id="aggiungere-un-canale-webdav" tabindex="-1">Aggiungere un canale WebDAV <a class="header-anchor" href="#aggiungere-un-canale-webdav" aria-label="Permalink to &quot;Aggiungere un canale WebDAV&quot;">​</a></h1><h2 id="quando-usarlo" tabindex="-1">Quando usarlo <a class="header-anchor" href="#quando-usarlo" aria-label="Permalink to &quot;Quando usarlo&quot;">​</a></h2><p>Usa il canale WebDAV quando:</p><ul><li>hai un NAS, un cloud drive o un servizio storage con endpoint WebDAV.</li><li>vuoi salvare le immagini caricate in una tua cartella WebDAV.</li><li>vuoi che le credenziali restino nella tabella D1 <code>upload_channels</code>, senza esporle a lungo nel frontend.</li></ul><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>URL WebDAV lato server, per esempio <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Nome utente</td><td>Per accedere al servizio WebDAV.</td></tr><tr><td>Password</td><td>Per accedere al servizio WebDAV.</td></tr><tr><td>Modalità di autenticazione</td><td>Di default <code>Basic</code>. Usa <code>Digest</code> o negoziazione automatica solo se richiesto dal server.</td></tr><tr><td>Cartella di archiviazione</td><td>Cartella usata per salvare i file. Default <code>imgbed</code>.</td></tr></tbody></table><h2 id="dove-aggiungerlo" tabindex="-1">Dove aggiungerlo <a class="header-anchor" href="#dove-aggiungerlo" aria-label="Permalink to &quot;Dove aggiungerlo&quot;">​</a></h2><ol><li>Apri Impostazioni di sistema.</li><li>Vai a Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale in alto a destra.</li><li>Seleziona <code>WebDAV</code>.</li></ol><h2 id="riferimento-campi" tabindex="-1">Riferimento campi <a class="header-anchor" href="#riferimento-campi" aria-label="Permalink to &quot;Riferimento campi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Funzione</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>Nome canale</td><td>Nome riconoscibile, per esempio <code>koofr</code> o <code>nas</code>.</td><td>Sì</td></tr><tr><td>Endpoint</td><td>Endpoint WebDAV completo, incluso <code>https://</code>.</td><td>Sì</td></tr><tr><td>Nome utente</td><td>Utente di accesso WebDAV.</td><td>Sì</td></tr><tr><td>Password</td><td>Password WebDAV.</td><td>Sì</td></tr><tr><td>Modalità di autenticazione</td><td>Di solito <code>Basic</code>; usa <code>Digest</code> se il server richiede digest authentication.</td><td>Sì</td></tr><tr><td>Cartella di archiviazione</td><td>Cartella dove salvare i file. Default <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="esempio-fie-nl-tab-digital" tabindex="-1">Esempio: fie.nl.tab.digital <a class="header-anchor" href="#esempio-fie-nl-tab-digital" aria-label="Permalink to &quot;Esempio: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-crea-una-password-per-app" tabindex="-1">1. Crea una password per app <a class="header-anchor" href="#_1-crea-una-password-per-app" aria-label="Permalink to &quot;1. Crea una password per app&quot;">​</a></h3><p>Apri le impostazioni di sicurezza dell&#39;account, trova le password applicative e crea una nuova password.</p><p><img src="'+e+'" alt="Crea password app" loading="lazy"></p><p>Dopo la creazione, copiala e salvala subito. Di norma viene mostrata una sola volta.</p><p><img src="'+i+'" alt="Salva la nuova password app" loading="lazy"></p><h3 id="_2-compila-webdav-in-imgbed" tabindex="-1">2. Compila WebDAV in ImgBed <a class="header-anchor" href="#_2-compila-webdav-in-imgbed" aria-label="Permalink to &quot;2. Compila WebDAV in ImgBed&quot;">​</a></h3><p>Torna in ImgBed e aggiungi un canale WebDAV:</p><table tabindex="0"><thead><tr><th>Campo UI</th><th>Valore</th></tr></thead><tbody><tr><td>Endpoint</td><td>URL WebDAV fornito da <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Nome utente</td><td>Il tuo nome utente WebDAV.</td></tr><tr><td>Password</td><td>La password app appena creata.</td></tr><tr><td>Modalità di autenticazione</td><td>Inizia con <code>Basic</code> nella maggior parte dei casi.</td></tr><tr><td>Cartella di archiviazione</td><td>Default <code>imgbed</code>; puoi usare anche una cartella personalizzata.</td></tr></tbody></table><p><img src="'+t+'" alt="Compila configurazione" loading="lazy"></p><h2 id="file-grandi-e-upload-a-chunk" tabindex="-1">File grandi e upload a chunk <a class="header-anchor" href="#file-grandi-e-upload-a-chunk" aria-label="Permalink to &quot;File grandi e upload a chunk&quot;">​</a></h2><p>Il canale WebDAV usa un vero upload a chunk basato su sessione.</p><p>I file piccoli vengono caricati come un unico file completo. I file oltre 64 MiB vengono divisi automaticamente in parti da circa 10 MiB e caricati in una cartella remota dedicata ai chunk.</p><p>Il servizio WebDAV non deve supportare <code>partial update</code> né scritture basate su offset. ImgBed non unisce i chunk in un unico file remoto: salva un manifest e, quando il file viene richiesto, legge i chunk in ordine.</p><p>In pratica:</p><table tabindex="0"><thead><tr><th>Dimensione file</th><th>Metodo di upload</th><th>Struttura remota</th></tr></thead><tbody><tr><td>64 MiB o meno</td><td>Upload normale</td><td>Un file completo</td></tr><tr><td>Oltre 64 MiB</td><td>Upload a chunk basato su sessione</td><td>Cartella con più file chunk</td></tr></tbody></table><p>La cartella dei chunk riguarda solo il layout sullo storage remoto. L&#39;URL in ImgBed non cambia: gli utenti continuano ad aprire il file tramite il link originale <code>/file/...</code>.</p><h2 id="passaggi-di-configurazione" tabindex="-1">Passaggi di configurazione <a class="header-anchor" href="#passaggi-di-configurazione" aria-label="Permalink to &quot;Passaggi di configurazione&quot;">​</a></h2><ol><li>Apri Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale.</li><li>Seleziona <code>WebDAV</code>.</li><li>Inserisci un nome canale chiaro, per esempio <code>koofr</code>.</li><li>Inserisci l&#39;endpoint WebDAV, per esempio <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Inserisci nome utente e password.</li><li>Lascia la modalità di autenticazione su <code>Basic</code> di default.</li><li>Lascia la cartella su <code>imgbed</code> o cambiala con una tua.</li><li>Salva.</li><li>Dopo il salvataggio controlla la scheda, interroga la capacità se disponibile e carica un file di prova.</li></ol><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controllo</th><th>Come verificare</th></tr></thead><tbody><tr><td>Scheda canale</td><td>Dopo il salvataggio compare una scheda WebDAV.</td></tr><tr><td>Canale attivo</td><td>L&#39;interruttore sulla scheda resta acceso.</td></tr><tr><td>Credenziali salvate</td><td>La vista dettaglio mostra Endpoint, nome utente, modalità di autenticazione e cartella.</td></tr><tr><td>Upload piccolo</td><td>Carica un&#39;immagine di prova e verifica che compaia nella cartella WebDAV.</td></tr><tr><td>Regola file grandi</td><td>I file sopra 64 MiB usano l&#39;upload a chunk e creano una cartella chunk remota.</td></tr><tr><td>Quota</td><td>Se il server supporta le informazioni di capacità, la query mostra spazio usato e totale.</td></tr></tbody></table><p><img src="'+o+`" alt="Quota interrogata correttamente" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="perche-i-file-webdav-grandi-creano-una-cartella-chunk" tabindex="-1">Perché i file WebDAV grandi creano una cartella chunk? <a class="header-anchor" href="#perche-i-file-webdav-grandi-creano-una-cartella-chunk" aria-label="Permalink to &quot;Perché i file WebDAV grandi creano una cartella chunk?&quot;">​</a></h3><p>È l&#39;attuale metodo di archiviazione dei file grandi.</p><p>I file oltre 64 MiB non vengono uniti in un unico file remoto. Sono salvati come cartella di chunk. ImgBed registra il manifest e restituisce il contenuto completo leggendo i chunk in ordine.</p><h3 id="cosa-controllo-se-l-upload-di-file-grandi-fallisce" tabindex="-1">Cosa controllo se l&#39;upload di file grandi fallisce? <a class="header-anchor" href="#cosa-controllo-se-l-upload-di-file-grandi-fallisce" aria-label="Permalink to &quot;Cosa controllo se l&#39;upload di file grandi fallisce?&quot;">​</a></h3><p>Controlla prima Endpoint, nome utente, password e cartella di archiviazione. Poi verifica che il servizio WebDAV consenta creazione di cartelle, scrittura e lettura dei file.</p><p>Se la query di capacità fallisce ma l&#39;upload di file piccoli funziona, il server potrebbe semplicemente non supportare o limitare il report della capacità. Non significa necessariamente che l&#39;upload non sia disponibile.</p><h3 id="quale-modalita-di-autenticazione-scegliere" tabindex="-1">Quale modalità di autenticazione scegliere? <a class="header-anchor" href="#quale-modalita-di-autenticazione-scegliere" aria-label="Permalink to &quot;Quale modalità di autenticazione scegliere?&quot;">​</a></h3><p>Parti da <code>Basic</code>.</p><p>Se il server richiede esplicitamente digest authentication, usa <code>Digest</code>.</p><p>Se non sei sicuro, usa la negoziazione automatica.</p><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prepara endpoint WebDAV, nome utente e password</span></span>
<span class="line"><span>-&gt; Apri Impostazioni di caricamento</span></span>
<span class="line"><span>-&gt; Aggiungi canale</span></span>
<span class="line"><span>-&gt; Seleziona WebDAV</span></span>
<span class="line"><span>-&gt; Inserisci Endpoint / nome utente / password</span></span>
<span class="line"><span>-&gt; Lascia Basic come modalità predefinita</span></span>
<span class="line"><span>-&gt; Lascia imgbed come cartella predefinita</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Interroga la capacità</span></span>
<span class="line"><span>-&gt; Carica un file di prova</span></span></code></pre></div>`,45)])])}const z=n(c,[["render",s]]);export{v as __pageData,z as default};
